def brainfuck(code: str, inp: str = "") -> str:
    tape = [0]
    ptr = 0
    ip = 0
    in_ptr = 0
    out = []

    jumps = {}
    stack = []
    for i, c in enumerate(code):
        if c == "[":
            stack.append(i)
        elif c == "]":
            j = stack.pop()
            jumps[i] = j
            jumps[j] = i

    while ip < len(code):
        c = code[ip]

        if c == ">":
            ptr += 1
            if ptr == len(tape):
                tape.append(0)
        elif c == "<":
            ptr = max(0, ptr - 1)
        elif c == "+":
            tape[ptr] = (tape[ptr] + 1) % 256
        elif c == "-":
            tape[ptr] = (tape[ptr] - 1) % 256
        elif c == ".":
            out.append(chr(tape[ptr]))
        elif c == ",":
            tape[ptr] = ord(inp[in_ptr]) if in_ptr < len(inp) else 0
            in_ptr += 1
        elif c == "[":
            if tape[ptr] == 0:
                ip = jumps[ip]
        elif c == "]":
            if tape[ptr] != 0:
                ip = jumps[ip]

        ip += 1

    return "".join(out)
